<?php
require_once __DIR__ . '/bootstrap.php';
ensure_logged_in();
$pasienId=(int)($_GET['pasien_id'] ?? 0);
$pasien=db_fetch_one("SELECT * FROM pasien WHERE id=?",[$pasienId]);
if(!$pasien){ die('Pasien tidak ditemukan.'); }
$kunjungan=db_fetch_all("SELECT * FROM kunjungan WHERE pasien_id=? ORDER BY tanggal DESC",[$pasienId]);
$invoice=db_fetch_all("SELECT * FROM invoice WHERE pasien_id=? ORDER BY tanggal DESC",[$pasienId]);
?><!doctype html><html lang="id"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Riwayat Pasien</title><style>body{font-family:Arial,sans-serif;background:#f8fbff;margin:0}.wrap{max-width:1100px;margin:0 auto;padding:24px}.card{background:#fff;border:1px solid #e2e8f0;border-radius:24px;padding:20px;box-shadow:0 14px 30px rgba(15,23,42,.06);margin-bottom:18px}.table{width:100%;border-collapse:collapse}.table th,.table td{padding:12px;border-bottom:1px solid #e2e8f0;text-align:left}</style></head><body><div class="wrap"><div class="card"><h1 style="margin:0 0 8px">Riwayat Pasien</h1><div><strong><?= e($pasien['no_rm']) ?></strong> - <?= e($pasien['nama']) ?></div><div><?= e($pasien['alamat']) ?></div></div><div class="card"><h2>Kunjungan</h2><table class="table"><thead><tr><th>Tanggal</th><th>Diagnosa</th><th>Tindakan</th></tr></thead><tbody><?php foreach($kunjungan as $k): ?><tr><td><?= e($k['tanggal']) ?></td><td><?= e($k['diagnosa']) ?></td><td><?= nl2br(e($k['tindakan'])) ?></td></tr><?php endforeach; if(!$kunjungan): ?><tr><td colspan="3">Belum ada kunjungan.</td></tr><?php endif; ?></tbody></table></div><div class="card"><h2>Invoice</h2><table class="table"><thead><tr><th>No Invoice</th><th>Tanggal</th><th>Total</th><th>Status</th></tr></thead><tbody><?php foreach($invoice as $i): ?><tr><td><?= e($i['no_invoice']) ?></td><td><?= e($i['tanggal']) ?></td><td><?= e(rupiah($i['total'])) ?></td><td><?= e($i['status_bayar']) ?></td></tr><?php endforeach; if(!$invoice): ?><tr><td colspan="4">Belum ada invoice.</td></tr><?php endif; ?></tbody></table></div></div></body></html>